import React, { useContext, useState, useEffect, useRef } from "react";
import { Link, graphql } from "gatsby";
import Layout, { LangContext } from "../components/Layout";
import SEO from "../components/SEO";
import DataPanel from "../components/DataPanel";
import { langSlug } from "../utils/i18n";

/** Format a date/timestamp into client-local time */
function LocalDate({ date, timestamp }) {
  const [formatted, setFormatted] = React.useState(date || "—");
  React.useEffect(() => {
    const raw = timestamp || date;
    if (!raw) { setFormatted("— "); return; }
    try {
      const iso = raw.includes("T") ? raw : `${raw}T00:00:00Z`;
      const d = new Date(iso);
      if (isNaN(d.getTime())) { setFormatted(raw); return; }
      setFormatted(d.toLocaleDateString(undefined, { year: "numeric", month: "short", day: "numeric" }) + " " + d.toLocaleTimeString(undefined, { hour: "2-digit", minute: "2-digit", hour12: false }));
    } catch { setFormatted(raw); }
  }, [date, timestamp]);
  return <>{formatted}</>;
}

const ShareButtons = ({ title, url, lang }) => {
  const [copied, setCopied] = useState(false);
  const l = (vi, en) => (lang === "vi" ? vi : en);

  const encoded = encodeURIComponent(url);
  const text = encodeURIComponent(`${title} — Bobbie Intelligence`);

  const canShare = typeof navigator !== "undefined" && navigator.share;

  const handleShareOrCopy = async () => {
    // iOS Safari: use native share sheet (clipboard API is broken in Safari/PWA)
    if (canShare) {
      try {
        await navigator.share({ title, url });
        return;
      } catch (e) {
        // User cancelled share sheet — do nothing
        if (e.name === "AbortError") return;
        // Fall through to clipboard fallback
      }
    }

    // Desktop / non-share browsers: copy to clipboard
    try {
      await navigator.clipboard.writeText(url);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // Last resort: execCommand hack
      const ta = document.createElement("textarea");
      ta.value = url;
      ta.setAttribute("readonly", "");
      ta.style.cssText = "position:fixed;left:-9999px;top:-9999px;opacity:0";
      document.body.appendChild(ta);
      ta.select();
      ta.setSelectionRange(0, url.length);
      let ok = false;
      try { ok = document.execCommand("copy"); } catch {}
      document.body.removeChild(ta);
      if (ok) {
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      }
    }
  };

  return (
    <div className="share-bar">
      <span className="share-label">{l("Chia sẻ:", "Share:")}</span>
      <a
        className="share-btn share-twitter"
        href={`https://twitter.com/intent/tweet?url=${encoded}&text=${text}`}
        target="_blank"
        rel="noopener noreferrer"
        title="X / Twitter"
      >
        𝕏
      </a>
      <a
        className="share-btn share-telegram"
        href={`https://t.me/share/url?url=${encoded}&text=${text}`}
        target="_blank"
        rel="noopener noreferrer"
        title="Telegram"
      >
        ✈️
      </a>
      <a
        className="share-btn share-facebook"
        href={`https://www.facebook.com/sharer/sharer.php?u=${encoded}`}
        target="_blank"
        rel="noopener noreferrer"
        title="Facebook"
      >
        f
      </a>
      <a
        className="share-btn share-linkedin"
        href={`https://www.linkedin.com/sharing/share-offsite/?url=${encoded}`}
        target="_blank"
        rel="noopener noreferrer"
        title="LinkedIn"
      >
        in
      </a>
      <button
        className={`share-btn share-copy ${copied ? "share-copied" : ""}`}
        onClick={handleShareOrCopy}
        title={canShare ? l("Chia sẻ", "Share") : l("Sao chép liên kết", "Copy link")}
      >
        {copied ? "✓" : "🔗"}
      </button>
    </div>
  );
};

const TTSControls = ({ lang }) => {
  const [speaking, setSpeaking] = useState(false);
  const [paused, setPaused] = useState(false);
  const [volume, setVolume] = useState(1.0);
  const volumeRef = useRef(1.0);
  const l = (vi, en) => (lang === "vi" ? vi : en);

  // Stop TTS on unmount (page navigation)
  useEffect(() => {
    return () => {
      if ("speechSynthesis" in window) {
        window.speechSynthesis.cancel();
      }
    };
  }, []);

  const handleVolumeChange = (val) => {
    setVolume(val);
    volumeRef.current = val;
  };

  const handlePlayPause = () => {
    if (!("speechSynthesis" in window)) {
      alert(l("Trình duyệt không hỗ trợ đọc văn bản", "Your browser does not support text-to-speech"));
      return;
    }

    if (speaking) {
      if (paused) {
        window.speechSynthesis.resume();
        setPaused(false);
      } else {
        window.speechSynthesis.pause();
        setPaused(true);
      }
      return;
    }

    const content = document.querySelector(".report-content");
    if (!content) return;
    const text = content.innerText;
    if (!text.trim()) return;

    // Chunk text into ~200 char segments for better TTS quality
    const chunks = [];
    const lines = text.split(/\n+/);
    let current = "";
    for (const line of lines) {
      if ((current + " " + line).length > 200) {
        if (current) chunks.push(current);
        current = line;
      } else {
        current = current ? current + " " + line : line;
      }
    }
    if (current) chunks.push(current);

    let idx = 0;
    const speakNext = () => {
      if (idx >= chunks.length) {
        setSpeaking(false);
        setPaused(false);
        return;
      }
      const utterance = new SpeechSynthesisUtterance(chunks[idx]);
      utterance.lang = lang === "vi" ? "vi-VN" : "en-US";
      utterance.rate = 1.0;
      utterance.pitch = 1.0;
      utterance.volume = volumeRef.current;

      const voices = window.speechSynthesis.getVoices();
      const preferred = voices.find(
        (v) => v.lang.startsWith(lang === "vi" ? "vi" : "en") && !v.localService
      ) || voices.find(
        (v) => v.lang.startsWith(lang === "vi" ? "vi" : "en")
      );
      if (preferred) utterance.voice = preferred;

      utterance.onend = () => {
        idx++;
        speakNext();
      };
      utterance.onerror = () => {
        setSpeaking(false);
        setPaused(false);
      };

      window.speechSynthesis.speak(utterance);
    };

    window.speechSynthesis.cancel();
    setSpeaking(true);
    setPaused(false);
    speakNext();
  };

  const handleStop = () => {
    window.speechSynthesis.cancel();
    setSpeaking(false);
    setPaused(false);
  };

  const volumeIcon = volume === 0 ? "🔇" : volume < 0.4 ? "🔈" : volume < 0.7 ? "🔉" : "🔊";

  return (
    <div className="tts-controls">
      <button
        className={`share-btn tts-btn ${speaking ? "tts-active" : ""}`}
        onClick={speaking ? (paused ? handlePlayPause : handleStop) : handlePlayPause}
        title={
          speaking
            ? paused
              ? l("Tiếp tục đọc", "Resume")
              : l("Dừng đọc", "Stop")
            : l("Đọc to", "Read aloud")
        }
      >
        {speaking ? (paused ? "▶️" : "⏹️") : "🔊"}
      </button>
      {speaking && !paused && (
        <button
          className="share-btn tts-btn tts-active"
          onClick={handlePlayPause}
          title={l("Tạm dừng", "Pause")}
        >
          ⏸️
        </button>
      )}
      <div className="tts-volume">
        <span className="tts-volume-icon">{volumeIcon}</span>
        <input
          type="range"
          className="tts-volume-slider"
          min="0"
          max="1"
          step="0.1"
          value={volume}
          onChange={(e) => handleVolumeChange(parseFloat(e.target.value))}
          title={l("Âm lượng", "Volume")}
        />
      </div>
    </div>
  );
};

const ReportDetailTemplate = ({ data, pageContext }) => {
  const { lang } = useContext(LangContext);
  const { category, categoryLabel, categoryIcon } = pageContext;
  const report = data.markdownRemark;

  const title =
    report?.frontmatter?.title ||
    report?.fields?.inferredTitle ||
    `${categoryLabel} Report`;
  const l = (vi, en) => (lang === "vi" ? vi : en);

  const reportUrl =
    typeof window !== "undefined"
      ? `https://solo.engineer${window.location.pathname}`
      : `https://solo.engineer${report?.fields?.slug || ""}`;

  return (
    <Layout>
      <article className="report-detail">
        <nav className="report-breadcrumb" aria-label="Breadcrumb">
          <Link to={langSlug("/", lang)}>
            {l("Bảng điều khiển", "Dashboard")}
          </Link>
          <span className="breadcrumb-sep">›</span>
          <Link to={langSlug("/reports/", lang)}>
            {l("Báo cáo", "Reports")}
          </Link>
          <span className="breadcrumb-sep">›</span>
          <Link to={langSlug(`/reports/${category}/`, lang)}>
            {categoryIcon} {categoryLabel}
          </Link>
          <span className="breadcrumb-sep">›</span>
          <span className="breadcrumb-current">
            {report?.fields?.date || l("Báo cáo", "Report")}
          </span>
        </nav>

        <header className="report-header">
          <div className="report-title-row">
            <TTSControls lang={lang} />
            <h1>{title}</h1>
          </div>
          <div className="report-meta">
            <span className="report-meta-item">
              📁 {categoryIcon} {categoryLabel}
            </span>
            <span className="report-meta-item">
              📅{" "}
              <LocalDate date={report?.frontmatter?.date || report?.fields?.date} timestamp={report?.frontmatter?.timestamp || report?.fields?.sortTimestamp} />
            </span>
            <span className="report-meta-item">👤 Bobbie Intelligence</span>
          </div>
          <ShareButtons title={title} url={reportUrl} lang={lang} />
        </header>

        <DataPanel title={l("Nội dung Báo cáo", "Report Content")}>
          <div
            className="report-content markdown-body"
            dangerouslySetInnerHTML={{ __html: report?.html || "" }}
          />
        </DataPanel>

        <div className="share-bar-bottom">
          <ShareButtons title={title} url={reportUrl} lang={lang} />
        </div>
      </article>
    </Layout>
  );
};

export default ReportDetailTemplate;

export const Head = ({ data, pageContext, location }) => {
  const report = data.markdownRemark;
  const { categoryLabel, lang } = pageContext;
  const title =
    report?.frontmatter?.title || `${categoryLabel} Report`;
  const desc = report?.excerpt
    ? report.excerpt.substring(0, 160)
    : `Intelligence report from Bobbie Intelligence: ${title}`;

  return (
    <SEO
      title={`${title} — Bobbie Intelligence`}
      description={desc}
      path={report?.fields?.slug || "/"}
      lang={lang || (location?.pathname?.startsWith("/en") ? "en" : "vi")}
      article={{
        publishedTime: report?.frontmatter?.date || report?.fields?.date,
        author: "Bobbie Intelligence",
        category: categoryLabel,
      }}
    />
  );
};

export const query = graphql`
  query ReportDetail($id: String!) {
    markdownRemark(id: { eq: $id }) {
      id
      html
      excerpt
      fields {
        slug
        category
        categoryLabel
        categoryIcon
        date
        sortTimestamp
        lang
      }
      frontmatter {
        title
        date
        timestamp
      }
    }
  }
`;
